# DLT pipeline example (simplified)
import dlt
from pyspark.sql.functions import col, from_json

# Bronze: Ingest raw multi-tenant data from S3
@dlt.table
def bronze_raw():
    return (
        spark.readStream.format("cloudFiles")
            .option("cloudFiles.format", "json")
            .schema(bronze_schema)
            .load("s3://bucket/raw/")
    )

# Silver: Apply tenant-specific transformations with CDC
@dlt.table(
    name="silver_conformed",
    expectations=[
        {"name": "valid_tenant_id", "assertion": "tenant_id IS NOT NULL"},
        {"name": "valid_timestamp", "assertion": "event_time > '2020-01-01'"}
    ]
)
def silver_conformed():
    return (
        dlt.readStream("bronze_raw")
            .withColumn("ingestion_timestamp", current_timestamp())
            .withColumn("tenant_id", col("_metadata").getItem("tenant_id"))
    )

# Gold: Create feature store table for ML serving
@dlt.table
def gold_feature_store():
    return (
        dlt.readStream("silver_conformed")
            .groupBy("tenant_id", "customer_id")
            .agg(
                collect_list("event_type").alias("event_history"),
                sum("amount").alias("total_amount"),
                max("event_time").alias("last_event")
            )
    )

# Idempotent MERGE for late-arriving data
def upsert_to_feature_store(batch_df, batch_id):
    batch_df.writeStream
        .format("delta")
        .outputMode("merge")
        .option("checkpointLocation", checkpoint_path)
        .foreachBatch(lambda df, bid: df.mergeInto(
            target_table, 
            "target.customer_id = source.customer_id AND target.tenant_id = source.tenant_id"
        ).whenMatchedUpdateAll().whenNotMatchedInsertAll())
        .start()
```

